? " .. player.Name .. " unequipped " .. gearName) return true, "Unequipped " .. gearName end GetGearInventory.OnServerInvoke = function(player) if not player or not player.Parent then return {} end return getPlayerGearInventory(player) end GetFormattedGearInventory.OnServerInvoke = function(player) if not player or not player.Parent then return {} end local inventory = getPlayerGearInventory(player) local data = getPlayerData(player) local formattedInventory = {} for _, gearId in ipairs(inventory) do local gearData = GearData.Gears[gearId] if gearData then table.insert(formattedInventory, { id = gearId, name = gearData.name, description = gearData.description, rarity = gearData.rarity, luckBoost = gearData.luckBoost, rollPenalty = gearData.rollPenalty, isEquipped = (data.equippedGear == gearId), color = gearData.color }) end end return formattedInventory end GetRawGearData.OnServerInvoke = function(player) if not player or not player.Parent then return {} end local data = getPlayerData(player) return { equippedGear = data.equippedGear, gearInventory = data.gearInventory or {}, autoAddGear = data.autoAddGear } end CheckBrainrotCount.OnServerInvoke = function(player, brainrotType) if not player or not player.Parent then return 0 end local data = getPlayerData(player) return data.craftingProgress[brainrotType] or 0 end spawn(function() while true do wait(SAVE_INTERVAL) for userId, needsSave in pairs(saveQueue) do if needsSave then local player = Players:GetPlayerByUserId(userId) if player and player.Parent then spawn(function() savePlayerData(player, false) end) end end end end end) local function onPlayerAdded(player) print("?? Player " .. player.Name .. " joined, initializing gear data...") playerData[player.UserId] = nil playerDebounce[player.UserId] = false saveQueue[player.UserId] = false lastSaveTime[player.UserId] = 0 spawn(function() loadPlayerData(player) wait(1) if player and player.Parent then updatePlayerLuckBoost(player) end end) end local function onPlayerRemoving(player) print("?? Player " .. player.Name .. " leaving, saving gear data...") if playerData[player.UserId] then savePlayerData(player, true) end spawn(function() wait(5) playerData[player.UserId] = nil playerDebounce[player.UserId] = nil saveQueue[player.UserId] = nil lastSaveTime[player.UserId] = nil end) end Players.PlayerAdded:Connect(onPlayerAdded) Players.PlayerRemoving:Connect(onPlayerRemoving) for _, player in ipairs(Players:GetPlayers()) do spawn(function() onPlayerAdded(player) end) end _G.GetPlayerGearData = function(userId) return playerData[userId] end _G.GetPlayerEquippedGear = function(userId) local data = playerData[userId] return data and data.equippedGear end _G.UpdatePlayerLuckBoost = function(userId) local player = Players:GetPlayerByUserId(userId) if player then return updatePlayerLuckBoost(player) end return 0, 0 end _G.AddBrainrotToPlayer = function(userId, brainrotType, amount, targetGearId) local player = Players:GetPlayerByUserId(userId) if player then return AddBrainrot.OnServerInvoke(player, brainrotType, amount, targetGearId) end return false, "Player not found" end _G.ProcessExistingInventoryForAutoAdd = processExistingInventoryForAutoAdd local autoSaveConnection = RunService.Heartbeat:Connect(function() local now = tick() for userId, needsSave in pairs(saveQueue) do if needsSave and lastSaveTime[userId] and (now - lastSaveTime[userId]) >= SAVE_INTERVAL then local player = Players:GetPlayerByUserId(userId) if player and player.Parent then spawn(function() savePlayerData(player, false) end) end end end end) game:BindToClose(function() print("?? Server shutting down, saving all gear data...") if autoSaveConnection then autoSaveConnection:Disconnect() end for userId, data in pairs(playerData) do if data then local player = Players:GetPlayerByUserId(userId) if player then spawn(function() savePlayerData(player, true) end) end end end wait(3) print("? Gear system shutdown complete") end) OpenGearMerchantGUI.OnServerEvent:Connect(function(player) if not player or not player.Parent then return end print("?? Opening gear merchant GUI for " .. player.Name) end) Players.PlayerAdded:Connect(function(player) player.Chatted:Connect(function(message) if player.Name == "i0nii_Chann" then if message == "/synctest" then print("?? SYNC TEST:") local autoAddGear = getPlayerData(player).autoAddGear print(" Auto-add gear: " .. tostring(autoAddGear)) if autoAddGear then local inventory = InventorySystem.GetPlayerInventory(player) print(" Current inventory items: " .. #inventory) for _, item in pairs(inventory) do local itemName = item.name or item.Name or "Unknown" local itemCount = item.count or item.Count or 1 print(" - " .. itemName .. " x" .. itemCount) end processExistingInventoryForAutoAdd(player) end elseif message == "/debugglobals" then print("?? DEBUG GLOBALS:") print("Available global functions:") for key, value in pairs(_G) do if type(value) == "function" then print(" - _G." .. key) end end elseif message:sub(1, 9) == "/syncadd " then local brainrotName = message:sub(10) print("?? SYNC ADD TEST: " .. brainrotName) local data = getPlayerData(player) if data.autoAddGear then local hasItem = InventorySystem.GetItemCount(player, brainrotName) print("Player has " .. hasItem .. "x " .. brainrotName) if hasItem > 0 then processExistingInventoryForAutoAdd(player) else print("? Player doesn't have " .. brainrotName .. " in inventory") end else print("? No auto-add gear enabled") end elseif message == "/forceprocess" then processExistingInventoryForAutoAdd(player) elseif message == "/testinventory" then TestInventory.OnServerInvoke(player) elseif message == "/testbrainrot" then TestBrainrotDefs.OnServerInvoke(player) end end end) end) print("? ALL ISSUES FIXED - Gear System loaded!") print("?? Fixed Issues:") print(" - ? Removed ALL InvokeServer calls from server-side") print(" - ? Enhanced inventory system detection with multiple methods") print(" - ? Better item name/count field detection") print(" - ? More robust inventory removal methods") print(" - ? Fixed _G.AddBrainrotToPlayer function") print(" - ? Better error handling throughout") print(" - ? Enhanced debugging output") print(" - ? CORRECTED ADMIN USERNAME: i0nii_Chann") print("?? Ready for production!") print("?? Admin commands: /synctest, /debugglobals, /syncadd [brainrot], /forceprocess, /testinventory, /testbrainrot")

-- Script: ServerScriptService>GearInventoryScript

local ReplicatedStorage = game:GetService("ReplicatedStorage") local Players = game:GetService("Players") local GearRemotes = ReplicatedStorage:WaitForChild("GearRemotes") local GetRawGearData = GearRemotes:FindFirstChild("GetRawGearData") or GearRemotes:WaitForChild("GetFormattedGearInventory") local LuckBoostEvent = ReplicatedStorage:WaitForChild("LuckBoostEvent") local GearData = require(ReplicatedStorage:WaitForChild("GearData")) local InventoryRemotes = ReplicatedStorage:FindFirstChild("InventoryRemotes") if not InventoryRemotes then InventoryRemotes = Instance.new("Folder") InventoryRemotes.Name = "InventoryRemotes" InventoryRemotes.Parent = ReplicatedStorage end local InventoryUpdated = InventoryRemotes:FindFirstChild("InventoryUpdated") or Instance.new("RemoteEvent") InventoryUpdated.Name = "InventoryUpdated" InventoryUpdated.Parent = InventoryRemotes local OpenInventory = ReplicatedStorage:FindFirstChild("OpenInventory") or Instance.new("RemoteEvent") OpenInventory.Name = "OpenInventory" OpenInventory.Parent = ReplicatedStorage local function getPlayerLuckFromGear(player) local gearData = nil local luckBoost = 0 local rollPenalty = 0 pcall(function() gearData = GetRawGearData:InvokeServer(player) end) if gearData and gearData.equippedGear then local gearInfo = GearData.Gears[gearData.equippedGear] if gearInfo then luckBoost = gearInfo.luckBoost or 0 rollPenalty = gearInfo.rollPenalty or 0 print("Player " .. player.Name .. " has gear equipped: +" .. luckBoost .. "% luck") end end return luckBoost, rollPenalty end local function updateAllPlayersLuckBoost() for _, player in pairs(Players:GetPlayers()) do local luckBoost, rollPenalty = getPlayerLuckFromGear(player) LuckBoostEvent:FireClient(player, luckBoost, rollPenalty) end end spawn(function() while wait(10) do updateAllPlayersLuckBoost() end end) OpenInventory.OnServerEvent:Connect(function(player) wait(0.5) local luckBoost, rollPenalty = getPlayerLuckFromGear(player) LuckBoostEvent:FireClient(player, luckBoost, rollPenalty) end) print("Gear Inventory Bridge loaded - connecting gear system with luck GUI")

