local ReplicatedStorage = game:GetService("ReplicatedStorage") local Players = game:GetService("Players") wait(2) print("?? Loading Auto-Add Integration...") if not _G.HandleAutoAdd then warn("? Gear system not found! Make sure GearSystem script is running.") return end local function onItemReceived(player, itemName, amount) if not player or not itemName then return end local handled = _G.HandleAutoAdd(player, itemName) if handled then print("? AUTO-ADD: Processed " .. itemName .. " for " .. player.Name) end end local originalFunctions = {} local inventoryFunctions = { "AddItemToInventory", "GiveItem", "AwardItem", "AddItem" } for _, funcName in pairs(inventoryFunctions) do if _G[funcName] then originalFunctions[funcName] = _G[funcName] _G[funcName] = function(playerOrUserId, itemName, amount, ...) local result = originalFunctions[funcName](playerOrUserId, itemName, amount, ...) local player = nil if type(playerOrUserId) == "number" then player = Players:GetPlayerByUserId(playerOrUserId) elseif typeof(playerOrUserId) == "Instance" and playerOrUserId:IsA("Player") then player = playerOrUserId end if player and itemName then spawn(function() wait(0.1) onItemReceived(player, itemName, amount or 1) end) end return result end print("? Hooked into " .. funcName .. " for auto-add") end end _G.TriggerAutoAdd = onItemReceived spawn(function() while true do wait(5) for _, player in pairs(Players:GetPlayers()) do if player and player.Parent then spawn(function() pcall(function() if _G.ProcessExistingInventoryForAutoAdd then _G.ProcessExistingInventoryForAutoAdd(player) end end) end) end end end end) print("? Auto-Add Integration loaded!") print("?? Available functions:") print(" - _G.TriggerAutoAdd(player, itemName, amount)") print(" - Automatic processing every 5 seconds") print(" - Hooked into common inventory functions")

