 print("?? LuckPotionSystem.lua is loading...") local ReplicatedStorage = game:GetService("ReplicatedStorage") local RunService = game:GetService("RunService") local Players = game:GetService("Players") local potionPickedUpEvent = ReplicatedStorage:FindFirstChild("PotionPickedUpEvent") if not potionPickedUpEvent then potionPickedUpEvent = Instance.new("RemoteEvent") potionPickedUpEvent.Name = "PotionPickedUpEvent" potionPickedUpEvent.Parent = ReplicatedStorage end local potionLuckUpdateEvent = ReplicatedStorage:FindFirstChild("PotionLuckUpdateEvent") if not potionLuckUpdateEvent then potionLuckUpdateEvent = Instance.new("RemoteEvent") potionLuckUpdateEvent.Name = "PotionLuckUpdateEvent" potionLuckUpdateEvent.Parent = ReplicatedStorage end local potionHoldEvent = ReplicatedStorage:FindFirstChild("PotionHoldEvent") if not potionHoldEvent then potionHoldEvent = Instance.new("RemoteEvent") potionHoldEvent.Name = "PotionHoldEvent" potionHoldEvent.Parent = ReplicatedStorage end local PotionSpawnNotification = ReplicatedStorage:FindFirstChild("PotionSpawnNotification") if not PotionSpawnNotification then PotionSpawnNotification = Instance.new("RemoteEvent") PotionSpawnNotification.Name = "PotionSpawnNotification" PotionSpawnNotification.Parent = ReplicatedStorage end local PotionArrowGuide = ReplicatedStorage:FindFirstChild("PotionArrowGuide") if not PotionArrowGuide then PotionArrowGuide = Instance.new("RemoteEvent") PotionArrowGuide.Name = "PotionArrowGuide" PotionArrowGuide.Parent = ReplicatedStorage end print("?? ? RemoteEvents created successfully") local POTION_SPAWN_LOCATIONS = { Vector3.new(155.936, 96.484, 139.402), Vector3.new(295.313, 96.484, 315.488), Vector3.new(453.037, 95.25, 107.278), Vector3.new(447.48, 95.518, -5.222), Vector3.new(199.596, 116.38, -35.937), Vector3.new(362.085, 190.342, 532.851), Vector3.new(334.098, 96.58, 539.604), Vector3.new(411.522, 126.192, 612.688), Vector3.new(532.718, 198.321, 552.231), Vector3.new(430.545, 223.377, 593.353), } local POTION_RESPAWN_TIME_MIN = 100 local POTION_RESPAWN_TIME_MAX = 600 local POTION_LUCK_BOOST = 35 local POTION_DURATION = 60 local FLOAT_HEIGHT = 3 local HOLD_TIME = 2 local MAX_POTIONS_AT_ONCE = 1 local SPAWN_CHANCE = 0.3 local ARROW_DURATION = 12 print("?? ?? Settings loaded - Max potions: " .. MAX_POTIONS_AT_ONCE) local activePotions = {} local playerBuffs = {} local spawnTimers = {} local activePotionCount = 0 local function notifyAndGuideVIPPlayers(position, potionName) print("?? ?? Notifying and guiding VIP players to potion at: " .. tostring(position)) local vipPlayers = {} if _G.HasPotionNotifications then for _, player in pairs(Players:GetPlayers()) do if _G.HasPotionNotifications(player) then table.insert(vipPlayers, player) print("?? ?? Found VIP player: " .. player.Name) end end else for _, player in pairs(Players:GetPlayers()) do if _G.CheckPlayerGamepassOwnership and _G.CheckPlayerGamepassOwnership(player, 1376797718) then table.insert(vipPlayers, player) print("?? ?? Found VIP player (fallback): " .. player.Name) end end end if #vipPlayers > 0 then print("?? ?? Sending notifications and arrows to " .. #vipPlayers .. " VIP players") for _, player in pairs(vipPlayers) do PotionSpawnNotification:FireClient(player, position) PotionArrowGuide:FireClient(player, { targetPosition = position, potionName = potionName, duration = ARROW_DURATION }) end else print("?? ?? No VIP players found to notify") end end local function findGroundLevel(position) print("?? ?? GROUND DETECTION for position: " .. tostring(position)) local testY = position.Y print("?? ?? Using original Y position: " .. testY) return testY end local function createLuckPotion(position, locationIndex, forceSpawn) print("?? ==========================================") print("?? ?? ATTEMPTING TO CREATE POTION at location " .. locationIndex) print("?? ?? Position: " .. tostring(position)) print("?? ?? Force spawn: " .. tostring(forceSpawn or false)) if not forceSpawn then if activePotionCount >= MAX_POTIONS_AT_ONCE then print("?? ?? Max potions reached (" .. MAX_POTIONS_AT_ONCE .. "), skipping spawn at location " .. locationIndex) local respawnDelay = math.random(60, 300) spawnTimers[locationIndex] = spawn(function() wait(respawnDelay) if POTION_SPAWN_LOCATIONS[locationIndex] then createLuckPotion(POTION_SPAWN_LOCATIONS[locationIndex], locationIndex) end spawnTimers[locationIndex] = nil end) return nil end if math.random() > SPAWN_CHANCE then print("?? ?? Spawn chance failed for location " .. locationIndex .. " (30% chance)") local respawnDelay = math.random(POTION_RESPAWN_TIME_MIN, POTION_RESPAWN_TIME_MAX) spawnTimers[locationIndex] = spawn(function() wait(respawnDelay) if POTION_SPAWN_LOCATIONS[locationIndex] then createLuckPotion(POTION_SPAWN_LOCATIONS[locationIndex], locationIndex) end spawnTimers[locationIndex] = nil end) return nil end else print("?? ?? FORCE SPAWN: Skipping capacity and chance checks") end local potionModel = ReplicatedStorage:FindFirstChild("Luck_Potion") if not potionModel then warn("?? ? ERROR: Luck_Potion model not found in ReplicatedStorage!") print("?? ?? Available models in ReplicatedStorage:") for _, child in pairs(ReplicatedStorage:GetChildren()) do print("?? - " .. child.Name .. " (" .. child.ClassName .. ")") end return nil end print("?? ? Found Luck_Potion model in ReplicatedStorage") local newPotion = potionModel:Clone() local potionName = "LuckPotion_" .. locationIndex .. "_" .. tick() newPotion.Name = potionName local adjustedPosition = Vector3.new(position.X, position.Y + FLOAT_HEIGHT, position.Z) print("?? ?? Original position: " .. position.X .. ", " .. position.Y .. ", " .. position.Z) print("?? ?? Adjusted position: " .. adjustedPosition.X .. ", " .. adjustedPosition.Y .. ", " .. adjustedPosition.Z) local originalPosition if potionModel.PrimaryPart then originalPosition = potionModel.PrimaryPart.Position print("?? ?? Using PrimaryPart position: " .. tostring(originalPosition)) else local mainPart = potionModel:FindFirstChildOfClass("BasePart") if mainPart then originalPosition = mainPart.Position print("?? ?? Using first BasePart position: " .. tostring(originalPosition)) else warn("?? ? ERROR: No BasePart found in Luck_Potion model!") print("?? ?? Children in model:") for _, child in pairs(potionModel:GetChildren()) do print("?? - " .. child.Name .. " (" .. child.ClassName .. ")") end return nil end end local offset = adjustedPosition - originalPosition local baseCFrames = {} local partCount = 0 print("?? ?? Moving parts with offset: " .. tostring(offset)) for _, part in pairs(newPotion:GetDescendants()) do if part:IsA("BasePart") then part.CFrame = part.CFrame + offset part.CanCollide = false part.Anchored = true baseCFrames[part] = part.CFrame partCount = partCount + 1 print("?? ?? Moved part: " .. part.Name .. " to " .. tostring(part.Position)) end end print("?? ? Moved " .. partCount .. " parts") local function addGreenGlow() local glowCount = 0 for _, part in pairs(newPotion:GetDescendants()) do if part:IsA("BasePart") then local greenLight = Instance.new("PointLight") greenLight.Name = "GreenGlow" greenLight.Color = Color3.fromRGB(0, 255, 0) greenLight.Brightness = 1 greenLight.Range = 8 greenLight.Parent = part glowCount = glowCount + 1 end end print("?? ?? Added green glow to " .. glowCount .. " parts") end addGreenGlow() local floatConnection local startTime = tick() floatConnection = RunService.Heartbeat:Connect(function() if newPotion and newPotion.Parent then local time = tick() - startTime local floatOffset = math.sin(time * 2) * 0.8 for part, baseCFrame in pairs(baseCFrames) do if part and part.Parent then local newPos = baseCFrame.Position + Vector3.new(0, floatOffset, 0) part.CFrame = CFrame.new(newPos, baseCFrame.LookVector) end end else floatConnection:Disconnect() end end) activePotions[newPotion] = { position = adjustedPosition, locationIndex = locationIndex, floatConnection = floatConnection, baseCFrames = baseCFrames } print("?? ?? Parenting potion to workspace...") newPotion.Parent = workspace activePotionCount = activePotionCount + 1 notifyAndGuideVIPPlayers(adjustedPosition, potionName) print("?? ? SUCCESS! RARE Luck potion spawned at location " .. locationIndex .. " (" .. activePotionCount .. "/" .. MAX_POTIONS_AT_ONCE .. " active)") print("?? ?? Final position: (" .. adjustedPosition.X .. ", " .. adjustedPosition.Y .. ", " .. adjustedPosition.Z .. ")") print("?? ??? Potion name: " .. newPotion.Name) print("?? ?? Potion parent: " .. tostring(newPotion.Parent)) print("?? ?? VIP players notified with arrow guidance!") print("?? ==========================================") return newPotion end local function pickupPotion(player, potion) local potionData = activePotions[potion] if not potionData then return end if playerBuffs[player.UserId] and tick() < playerBuffs[player.UserId].endTime then playerBuffs[player.UserId].endTime = tick() + POTION_DURATION potionPickedUpEvent:FireClient(player, POTION_LUCK_BOOST, POTION_DURATION) print("?? " .. player.Name .. "'s luck potion duration extended!") else playerBuffs[player.UserId] = { luckBoost = POTION_LUCK_BOOST, endTime = tick() + POTION_DURATION } potionPickedUpEvent:FireClient(player, POTION_LUCK_BOOST, POTION_DURATION) potionLuckUpdateEvent:FireClient(player, POTION_LUCK_BOOST) print("?? " .. player.Name .. " picked up a RARE luck potion! +" .. POTION_LUCK_BOOST .. "% luck for " .. POTION_DURATION .. "s") end if potionData.floatConnection then potionData.floatConnection:Disconnect() end activePotions[potion] = nil activePotionCount = activePotionCount - 1 if potion and potion.Parent then potion:Destroy() end local locationIndex = potionData.locationIndex local respawnDelay = math.random(POTION_RESPAWN_TIME_MIN, POTION_RESPAWN_TIME_MAX) spawnTimers[locationIndex] = spawn(function() print("?? Potion at location " .. locationIndex .. " will attempt respawn in " .. math.floor(respawnDelay/60) .. " minutes (" .. activePotionCount .. "/" .. MAX_POTIONS_AT_ONCE .. " active)") wait(respawnDelay) if POTION_SPAWN_LOCATIONS[locationIndex] then createLuckPotion(POTION_SPAWN_LOCATIONS[locationIndex], locationIndex) end spawnTimers[locationIndex] = nil end) end potionHoldEvent.OnServerEvent:Connect(function(player, potion) if potion and potion.Parent and activePotions[potion] then print("?? Received pickup request from " .. player.Name) pickupPotion(player, potion) end end) local function updatePlayerBuffs() local currentTime = tick() for playerId, buffData in pairs(playerBuffs) do if currentTime >= buffData.endTime then local player = Players:GetPlayerByUserId(playerId) if player then potionLuckUpdateEvent:FireClient(player, 0) print("?? " .. player.Name .. "'s luck potion expired") end playerBuffs[playerId] = nil end end end local function getPlayerPotionLuck(player) local buffData = playerBuffs[player.UserId] if buffData and tick() < buffData.endTime then return buffData.luckBoost end return 0 end local function forceSpawnAllPotions() print("?? ?? ADMIN: Force spawning ALL potions...") local spawnedCount = 0 for i, position in ipairs(POTION_SPAWN_LOCATIONS) do local potion = createLuckPotion(position, i, true) if potion then spawnedCount = spawnedCount + 1 end end print("?? ? ADMIN: Force spawned " .. spawnedCount .. "/" .. #POTION_SPAWN_LOCATIONS .. " potions") return spawnedCount end local function clearAllPotions() print("?? ??? ADMIN: Clearing all potions...") local clearedCount = 0 for potion, data in pairs(activePotions) do if data.floatConnection then data.floatConnection:Disconnect() end if potion and potion.Parent then potion:Destroy() clearedCount = clearedCount + 1 end end activePotions = {} for _, obj in pairs(workspace:GetChildren()) do if obj.Name and obj.Name:find("LuckPotion_") then obj:Destroy() clearedCount = clearedCount + 1 end end activePotionCount = 0 print("?? ? ADMIN: Cleared " .. clearedCount .. " potions") return clearedCount end local function listAllPotions() print("?? ?? ADMIN: Listing all active potions...") print("?? Active potion count: " .. activePotionCount) print("?? Tracked potions: " .. #activePotions) local workspacePotions = 0 for _, obj in pairs(workspace:GetChildren()) do if obj.Name and obj.Name:find("LuckPotion_") then workspacePotions = workspacePotions + 1 print("?? - " .. obj.Name .. " at " .. tostring(obj:FindFirstChildOfClass("BasePart") and obj:FindFirstChildOfClass("BasePart").Position or "unknown position")) end end print("?? Potions in workspace: " .. workspacePotions) return workspacePotions end local function spawnTestPotion(player) if not player or not player.Character or not player.Character:FindFirstChild("HumanoidRootPart") then return false, "Player or character not found" end local playerPosition = player.Character.HumanoidRootPart.Position local testPosition = playerPosition + Vector3.new(5, 0, 5) print("?? ?? ADMIN: Spawning test potion near " .. player.Name .. " at " .. tostring(testPosition)) local potion = createLuckPotion(testPosition, 999, true) if potion then return true, "Test potion spawned near you with arrow guidance" else return false, "Failed to spawn test potion" end end spawn(function() print("?? ?? Starting RARE potion spawn system with ARROW GUIDANCE...") print("?? Max potions at once: " .. MAX_POTIONS_AT_ONCE) print("?? Spawn chance: " .. (SPAWN_CHANCE * 100) .. "%") print("?? Respawn time: " .. math.floor(POTION_RESPAWN_TIME_MIN/60) .. "-" .. math.floor(POTION_RESPAWN_TIME_MAX/60) .. " minutes") print("?? Arrow guidance duration: " .. ARROW_DURATION .. " seconds") print("?? ADMIN TESTING MODE: Use admin commands to test potions") print("?? VIP arrow guidance enabled for Matteoooo's VIP players!") local shuffledLocations = {} for i, pos in ipairs(POTION_SPAWN_LOCATIONS) do table.insert(shuffledLocations, {pos = pos, index = i}) end for i = #shuffledLocations, 2, -1 do local j = math.random(i) shuffledLocations[i], shuffledLocations[j] = shuffledLocations[j], shuffledLocations[i] end for i, locationData in ipairs(shuffledLocations) do spawn(function() local initialDelay = math.random(60, 300) * i print("?? Location " .. locationData.index .. " scheduled for first attempt in " .. math.floor(initialDelay/60) .. " minutes") wait(initialDelay) createLuckPotion(locationData.pos, locationData.index) end) end ]] end) spawn(function() while true do wait(1) updatePlayerBuffs() end end) Players.PlayerRemoving:Connect(function(player) playerBuffs[player.UserId] = nil end) Players.PlayerAdded:Connect(function(player) player.Chatted:Connect(function(message) if player.Name == "juliovetta16" then if message == "!spawnpotions" then print("?? ?? ADMIN COMMAND: /spawnpotions") local count = forceSpawnAllPotions() print("?? ? RESULT: Spawned " .. count .. " potions with arrow guidance") elseif message == "!clearpotions" then print("?? ??? ADMIN COMMAND: /clearpotions") local count = clearAllPotions() print("?? ? RESULT: Cleared " .. count .. " potions") elseif message == "!listpotions" then print("?? ?? ADMIN COMMAND: /listpotions") listAllPotions() elseif message == "!testpotion" then print("?? ?? ADMIN COMMAND: /testpotion") local success, result = spawnTestPotion(player) print("?? ? RESULT: " .. result) elseif message == "!potionhelp" then print("?? ?? ADMIN COMMANDS:") print("?? !spawnpotions - Force spawn all potions with arrows") print("?? !clearpotions - Clear all potions") print("?? !listpotions - List all active potions") print("?? !testpotion - Spawn test potion with arrow guidance") print("?? !potionhelp - Show this help") end end end) end) _G.ForceSpawnAllPotions = forceSpawnAllPotions _G.CreateLuckPotion = function(position, locationIndex) return createLuckPotion(position, locationIndex, true) end _G.ResetPotionCount = function() activePotionCount = 0 end _G.getPlayerPotionLuck = getPlayerPotionLuck print("?? ? LuckPotionSystem.lua fully loaded - _G.ForceSpawnAllPotions available:", _G.ForceSpawnAllPotions ~= nil) print("?? ?? RARE Luck Potion System with ARROW GUIDANCE loaded!") print("?? ?? Spawn locations: " .. #POTION_SPAWN_LOCATIONS) print("?? ?? Max active potions: " .. MAX_POTIONS_AT_ONCE) print("?? ?? Arrow guidance: ENABLED (" .. ARROW_DURATION .. " seconds)") print("?? ?? VIP notifications: ENABLED") print("?? ????? ADMIN COMMANDS for juliovetta16:") print("?? /spawnpotions, /clearpotions, /listpotions, /testpotion, /potionhelp")

-- Script: ServerScriptService>DeathHandler

 local Players = game:GetService("Players") local ReplicatedStorage = game:GetService("ReplicatedStorage") print("?? Enhanced Death Handler System Loading...") local playerEquipmentState = {} local function savePlayerEquipment(player) local userId = player.UserId playerEquipmentState[userId] = { equippedGear = nil, gearLuckBoost = 0, equippedBrainrot = nil, chatTag = nil, gamepassLuckBoost = 0, timestamp = tick() } print("?? Saving equipment state for " .. player.Name .. "...") if _G.GetPlayerGearData then local gearData = _G.GetPlayerGearData(userId) if gearData and gearData.equippedGear then playerEquipmentState[userId].equippedGear = gearData.equippedGear local luckBoost = 0 if _G.GetGearLuckBoost then luckBoost = _G.GetGearLuckBoost(gearData.equippedGear) elseif _G.getCurrentBadgeLuckBoost then luckBoost = _G.getCurrentBadgeLuckBoost() end playerEquipmentState[userId].gearLuckBoost = luckBoost print("?? Saved equipped gear for " .. player.Name .. ": " .. gearData.equippedGear .. " (+" .. luckBoost .. "% luck)") end end local currentBoost = 0 local luckBoostEvent = ReplicatedStorage:FindFirstChild("LuckBoostEvent") if luckBoostEvent then if _G.getPlayerCurrentLuckBoost then currentBoost = _G.getPlayerCurrentLuckBoost(userId) or 0 end end playerEquipmentState[userId].gearLuckBoost = currentBoost if _G.CheckPlayerGamepassOwnership then local gamepassBoost = 0 if _G.CheckPlayerGamepassOwnership(player, 1376797718) then gamepassBoost = gamepassBoost + 100 end if _G.CheckPlayerGamepassOwnership(player, 1378491109) then gamepassBoost = gamepassBoost + 25 end playerEquipmentState[userId].gamepassLuckBoost = gamepassBoost print("?? Saved gamepass luck boost for " .. player.Name .. ": +" .. gamepassBoost .. "%") end if _G.GetPlayerChatTag then local chatTag = _G.GetPlayerChatTag(player) if chatTag then playerEquipmentState[userId].chatTag = chatTag print("?? Saved chat tag for " .. player.Name .. ": " .. chatTag) end end print("?? ? Equipment state saved for " .. player.Name) end local function restorePlayerEquipment(player) local userId = player.UserId local savedState = playerEquipmentState[userId] if not savedState then print("?? No saved state found for " .. player.Name) return end print("?? Restoring equipment for " .. player.Name .. "...") local character = player.Character or player.CharacterAdded:Wait() wait(3) if savedState.equippedGear and _G.GetPlayerGearData then local gearData = _G.GetPlayerGearData(userId) if gearData then gearData.equippedGear = savedState.equippedGear if _G.ApplyGearEffects then _G.ApplyGearEffects(player, savedState.equippedGear) end print("?? ? Restored equipped gear for " .. player.Name .. ": " .. savedState.equippedGear) end end wait(2) spawn(function() local attempts = 0 local maxAttempts = 5 while attempts < maxAttempts do attempts = attempts + 1 print("?? ?? Restoring luck boosts for " .. player.Name .. " (attempt " .. attempts .. "/" .. maxAttempts .. ")") if savedState.gearLuckBoost and savedState.gearLuckBoost > 0 then local luckBoostEvent = ReplicatedStorage:FindFirstChild("LuckBoostEvent") if luckBoostEvent then luckBoostEvent:FireClient(player, savedState.gearLuckBoost, 0) print("?? ?? Sent gear luck boost to " .. player.Name .. ": +" .. savedState.gearLuckBoost .. "%") end end if savedState.gamepassLuckBoost and savedState.gamepassLuckBoost > 0 then if _G.updateGamepassLuckBoost then end print("?? ?? Gamepass luck boost should restore automatically: +" .. savedState.gamepassLuckBoost .. "%") end wait(2) end print("?? ? Luck boost restoration complete for " .. player.Name) end) spawn(function() wait(4) if savedState.chatTag then print("?? ?? Chat tag should restore automatically: " .. savedState.chatTag) end end) end _G.ForceRestorePlayerEquipment = function(playerName) local player = Players:FindFirstChild(playerName) if player then restorePlayerEquipment(player) return true end return false end _G.GetSavedEquipmentState = function(playerName) local player = Players:FindFirstChild(playerName) if player then return playerEquipmentState[player.UserId] end return nil end Players.PlayerAdded:Connect(function(player) print("?? Setting up death handler for " .. player.Name) player.CharacterRemoving:Connect(function(character) print("?? Character removing for " .. player.Name .. ", saving equipment...") savePlayerEquipment(player) end) player.CharacterAdded:Connect(function(character) print("?? Character added for " .. player.Name .. ", scheduling restoration...") spawn(function() wait(2) restorePlayerEquipment(player) end) end) if player.Character then player.CharacterRemoving:Connect(function(character) print("?? (Existing character) Character removing for " .. player.Name .. ", saving equipment...") savePlayerEquipment(player) end) end end) Players.PlayerRemoving:Connect(function(player) print("?? Cleaning up equipment state for " .. player.Name) playerEquipmentState[player.UserId] = nil end) local serverPlayerLuckBoosts = {} local function updateServerLuckBoost(userId, gearLuckBoost, gamepassLuckBoost) serverPlayerLuckBoosts[userId] = { gearLuck = gearLuckBoost or 0, gamepassLuck = gamepassLuckBoost or 0, lastUpdated = tick() } end _G.getPlayerCurrentLuckBoost = function(userId) local data = serverPlayerLuckBoosts[userId] if data then return data.gearLuck end return 0 end _G.updateServerPlayerLuckBoost = function(userId, gearLuckBoost, gamepassLuckBoost) updateServerLuckBoost(userId, gearLuckBoost, gamepassLuckBoost) end local luckBoostEvent = ReplicatedStorage:FindFirstChild("LuckBoostEvent") if luckBoostEvent then end print("?? ? Enhanced Death Handler System Loaded!") print("?? ?? Debug commands available:") print("?? _G.ForceRestorePlayerEquipment('playerName')") print("?? _G.GetSavedEquipmentState('playerName')")

-- Script: ServerScriptService>AdminGUI_Server

 local Players = game:GetService("Players") local ReplicatedStorage = game:GetService("ReplicatedStorage") print("?? ADMIN GUI SERVER LOADING...") local ADMINS = { [377361486] = {name = "Admin1", level = 3}, [7180677868] = {name = "Admin2", level = 2}, [168722593] = {name = "Admin3", level = 6}, [299245694] = {name = "Admin4", level = 1}, [1710943863] = {name = "i0nii_Chann", level = 50}, } local function isAdmin(userId) return ADMINS[userId] ~= nil end local function getAdminLevel(userId) local admin = ADMINS[userId] return admin and admin.level or 0 end local function canUseGUI(userId) return getAdminLevel(userId) >= 5 end local AdminGUIRemotes = ReplicatedStorage:WaitForChild("AdminGUIRemotes", 10) if not AdminGUIRemotes then warn("?? ? AdminGUIRemotes not found!") return end local OpenAdminGUI = AdminGUIRemotes:WaitForChild("OpenAdminGUI", 5) if not OpenAdminGUI then warn("?? ? OpenAdminGUI not found!") return end print("?? ? Admin GUI Server loaded!") Players.PlayerAdded:Connect(function(player) print("?? Player joined: " .. player.Name .. " (ID: " .. player.UserId .. ")") if isAdmin(player.UserId) then local adminLevel = getAdminLevel(player.UserId) print("?? ? Admin detected: " .. player.Name .. " (Level " .. adminLevel .. ")") if canUseGUI(player.UserId) then wait(3) OpenAdminGUI:FireClient(player) print("?? ?? Sent admin GUI to " .. player.Name) end end end) for _, player in pairs(Players:GetPlayers()) do if isAdmin(player.UserId) and canUseGUI(player.UserId) then print("?? Setting up existing admin: " .. player.Name) spawn(function() wait(1) OpenAdminGUI:FireClient(player) print("?? ?? Sent admin GUI to existing player: " .. player.Name) end) end end print("?? ? ADMIN GUI SERVER READY!")

-- Script: ServerScriptService>GamePassRewardManager

 local Players = game:GetService("Players") local MarketplaceService = game:GetService("MarketplaceService") local ReplicatedStorage = game:GetService("ReplicatedStorage") local DataStoreService = game:GetService("DataStoreService") print("?? Loading Enhanced Gamepass Rewards Manager v2...") local RewardsDataStore = DataStoreService:GetDataStore("GamepassRewards_v3") local GamepassRemotes = ReplicatedStorage:WaitForChild("GamepassRemotes", 10) local CheckGamepassOwnership = GamepassRemotes and GamepassRemotes:WaitForChild("CheckGamepassOwnership", 5) local GearRemotes = ReplicatedStorage:FindFirstChild("GearRemotes") local AddGearToInventory, GetFormattedGearInventory if GearRemotes then AddGearToInventory = GearRemotes:FindFirstChild("AddGearToInventory") GetFormattedGearInventory = GearRemotes:FindFirstChild("GetFormattedGearInventory") end local InventoryRemotes = ReplicatedStorage:FindFirstChild("InventoryRemotes") local AddItemToInventory, UpdateInventory if InventoryRemotes then AddItemToInventory = InventoryRemotes:FindFirstChild("AddItemToInventory") UpdateInventory = InventoryRemotes:FindFirstChild("UpdateInventory") end local BrainrotRemotes = ReplicatedStorage:FindFirstChild("BrainrotRemotes") or ReplicatedStorage:FindFirstChild("BrainrotSettingsRemotes") print("?? System Status:") print(" Gamepass System: " .. (CheckGamepassOwnership and "?" or "?")) print(" Gear System: " .. (GearRemotes and "?" or "?")) print(" Inventory System: " .. (InventoryRemotes and "?" or "?")) print(" Brainrot System: " .. (BrainrotRemotes and "?" or "?")) local GAMEPASS_REWARDS = { [1376797718] = { name = "Matteoooo's VIP", rewards = { gears = { { id = "time_stop_sandals_liril", name = "Time-Stop Sandals of Liril™", rarity = "mythic", luckBoost = 100, rollPenalty = 0, description = "Legendary sandals that stop time itself", decalId = "rbxassetid://118478805616343" } }, brainrots = { "Sigma Gyatt Ohio", "Skibidi Toilet Rizz" }, items = { { id = "luck_potion_detector", name = "Luck Potion Detector", description = "Detects hidden luck potions", quantity = 1 } }, luckMultiplier = 2.0, chatTag = "[Matteoooo]" } }, [1378491109] = { name = "VIP", rewards = { gears = { { id = "blueberry_octopus_necklace", name = "Blueberry Octopus Necklace", rarity = "legendary", luckBoost = 25, rollPenalty = 0, description = "A mystical necklace with ocean powers", decalId = "rbxassetid://116907983558452" } }, luckMultiplier = 1.25, chatTag = "[VIP]" } }, [1374214026] = { name = "Starter Pack", rewards = { gears = { { id = "bobritos_rusty_medal", name = "Bobrito's Rusty Medal", rarity = "rare", luckBoost = 15, rollPenalty = 0, description = "A battle-worn medal of honor", decalId = "rbxassetid://125050552522929" } }, brainrots = { "Perfect Starter Bundle", "Din Din Melody" }, items = { { id = "u_din_din_track", name = "U Din Din Din Din Dun Ma Din Din Din Dun", description = "A catchy musical track", quantity = 1 }, { id = "tigrrullini_watermellini", name = "Tigrrullini Watermellini", description = "Refreshing watermelon treats", quantity = 2 } } } }, [1374405825] = { name = "Quick Roll", rewards = { features = { quickRoll = true } } } } local function hasReceivedRewards(player, gamepassId) local success, data = pcall(function() local key = "Player_" .. player.UserId return RewardsDataStore:GetAsync(key) or {} end) if success and data then return data[tostring(gamepassId)] == true end return false end local function markRewardsGranted(player, gamepassId) spawn(function() local success, err = pcall(function() local key = "Player_" .. player.UserId local data = RewardsDataStore:GetAsync(key) or {} data[tostring(gamepassId)] = true RewardsDataStore:SetAsync(key, data) end) if not success then warn("? Failed to save reward status for " .. player.Name .. ": " .. tostring(err)) else print("? Marked rewards as granted for gamepass " .. gamepassId) end end) end local function grantGear(player, gearData) print("?? Attempting to grant gear: " .. gearData.name) if AddGearToInventory then local success, result = pcall(function() return AddGearToInventory:InvokeServer(gearData) end) if success and result then print("? Granted gear via AddGearToInventory: " .. gearData.name) return true else print("? AddGearToInventory failed: " .. tostring(result)) end end if _G.AddPlayerGear then local success, result = pcall(function() return _G.AddPlayerGear(player, gearData) end) if success then print("? Granted gear via _G.AddPlayerGear: " .. gearData.name) return true end end local success, result = pcall(function() local gearFolder = player:FindFirstChild("PlayerGears") or player:FindFirstChild("Gears") if not gearFolder then gearFolder = Instance.new("Folder") gearFolder.Name = "PlayerGears" gearFolder.Parent = player end local gearValue = Instance.new("StringValue") gearValue.Name = gearData.id gearValue.Value = game:GetService("HttpService"):JSONEncode(gearData) gearValue.Parent = gearFolder return true end) if success then print("? Created gear data directly: " .. gearData.name) return true end warn("? All gear granting methods failed for: " .. gearData.name) return false end local function grantBrainrots(player, brainrotNames) if not brainrotNames or #brainrotNames == 0 then return true end print("?? Attempting to grant " .. #brainrotNames .. " brainrots") for _, brainrotName in ipairs(brainrotNames) do if UpdateInventory then local success, result = pcall(function() UpdateInventory:FireClient(player, { {name = brainrotName, discovered = true} }) return true end) if success then print("? Granted brainrot via UpdateInventory: " .. brainrotName) end end if _G.AddPlayerBrainrot then local success = pcall(function() _G.AddPlayerBrainrot(player, brainrotName) end) if success then print("? Granted brainrot via _G.AddPlayerBrainrot: " .. brainrotName) end end local playerData = player:FindFirstChild("BrainrotCollection") if not playerData then playerData = Instance.new("Folder") playerData.Name = "BrainrotCollection" playerData.Parent = player end local brainrotValue = Instance.new("BoolValue") brainrotValue.Name = brainrotName brainrotValue.Value = true brainrotValue.Parent = playerData print("? Added brainrot to player data: " .. brainrotName) end return true end local function grantGamepassRewards(player, gamepassId) local rewardConfig = GAMEPASS_REWARDS[gamepassId] if not rewardConfig then print("?? No rewards configured for gamepass " .. gamepassId) return end print("?? Granting " .. rewardConfig.name .. " rewards to " .. player.Name .. "...") local grantedItems = {} local allSuccessful = true if rewardConfig.rewards.gears then for _, gearData in ipairs(rewardConfig.rewards.gears) do if grantGear(player, gearData) then table.insert(grantedItems, "?? " .. gearData.name) else allSuccessful = false warn("? Failed to grant gear: " .. gearData.name) end end end if rewardConfig.rewards.brainrots then if grantBrainrots(player, rewardConfig.rewards.brainrots) then for _, brainrotName in ipairs(rewardConfig.rewards.brainrots) do table.insert(grantedItems, "?? " .. brainrotName) end else allSuccessful = false end end if rewardConfig.rewards.items then for _, itemData in ipairs(rewardConfig.rewards.items) do local success = false if AddItemToInventory then local result = pcall(function() return AddItemToInventory:InvokeServer(itemData.id, itemData.quantity or 1) end) if result then success = true end end if success then local quantity = itemData.quantity or 1 table.insert(grantedItems, "?? " .. quantity .. "x " .. itemData.name) else allSuccessful = false end end end if rewardConfig.rewards.features then if rewardConfig.rewards.features.quickRoll then local quickRollValue = player:FindFirstChild("QuickRollEnabled") if not quickRollValue then quickRollValue = Instance.new("BoolValue") quickRollValue.Name = "QuickRollEnabled" quickRollValue.Parent = player end quickRollValue.Value = true table.insert(grantedItems, "? Quick Roll Feature") end end if allSuccessful then markRewardsGranted(player, gamepassId) else warn("?? Some rewards failed to grant for " .. player.Name .. " - will retry next time") end if #grantedItems > 0 then local message = "?? " .. rewardConfig.name .. " rewards!\n" .. table.concat(grantedItems, "\n") print("? Granted " .. #grantedItems .. " rewards to " .. player.Name) print("?? Items granted: " .. table.concat(grantedItems, ", ")) else warn("? No rewards were successfully granted to " .. player.Name) end end local function checkAllGamepassRewards(player) if not CheckGamepassOwnership then warn("? CheckGamepassOwnership not available") return end print("?? Checking gamepass rewards for " .. player.Name .. "...") for gamepassId, config in pairs(GAMEPASS_REWARDS) do spawn(function() wait(1) local success, ownsGamepass = pcall(function() return CheckGamepassOwnership:InvokeServer(gamepassId) end) if success and ownsGamepass then if not hasReceivedRewards(player, gamepassId) then print("?? " .. player.Name .. " owns " .. config.name .. " but hasn't received rewards!") wait(2) grantGamepassRewards(player, gamepassId) else print("?? " .. player.Name .. " already received " .. config.name .. " rewards") end else print("?? " .. player.Name .. " doesn't own " .. config.name) end end) end end MarketplaceService.PromptGamePassPurchaseFinished:Connect(function(player, gamepassId, wasPurchased) if wasPurchased and GAMEPASS_REWARDS[gamepassId] then print("?? " .. player.Name .. " purchased gamepass " .. gamepassId .. "!") wait(3) grantGamepassRewards(player, gamepassId) end end) Players.PlayerAdded:Connect(function(player) print("?? " .. player.Name .. " joined") spawn(function() wait(8) checkAllGamepassRewards(player) end) end) Players.PlayerAdded:Connect(function(player) if player.Name == "theawesomestudentthatcodedawesomeness" then player.Chatted:Connect(function(message) if message == "/forcerewards" then print("?? FORCING REWARD CHECK for " .. player.Name) checkAllGamepassRewards(player) end end) end end) _G.CheckPlayerGamepassRewards = checkAllGamepassRewards _G.