a and data.gamepasses then for gamepassId, gamepassInfo in pairs(data.gamepasses) do if gamepassInfo.owned then local config = GAMEPASSES[gamepassId] if config and config.luckMultiplier then totalLuckMultiplier = totalLuckMultiplier * config.luckMultiplier print("? Applied luck from gamepass:", config.name, "Multiplier:", config.luckMultiplier) end end end end local luckBoostPercentage = (totalLuckMultiplier - 1) * 100 print("?? Final luck boost for", player.Name, ":", luckBoostPercentage, "%") if _G.updateGamepassLuckBoost then _G.updateGamepassLuckBoost(luckBoostPercentage) print("? Updated _G.updateGamepassLuckBoost") end local LuckBoostEvent = ReplicatedStorage:FindFirstChild("LuckBoostEvent") if LuckBoostEvent then pcall(function() LuckBoostEvent:FireClient(player, luckBoostPercentage, 0) end) print("? Fired LuckBoostEvent") end end local function savePlayerData(userId) local data = playerGamepassData[userId] if not data then return end local success, err = pcall(function() GamepassDataStore:SetAsync("player_" .. userId, data) end) if not success then warn("? Failed to save gamepass data for userId " .. userId .. ":", err) else print("? Saved gamepass data for userId:", userId) end end local function loadPlayerData(userId) local success, data = pcall(function() return GamepassDataStore:GetAsync("player_" .. userId) end) if success and data then playerGamepassData[userId] = data print("? Loaded existing gamepass data for userId:", userId) else playerGamepassData[userId] = { gamepasses = {}, giftedItems = {}, lastUpdate = os.time() } print("?? Created new gamepass data for userId:", userId) end return playerGamepassData[userId] end local function giveGearToPlayer(player, gearId) print("?? Attempting to give gear to", player.Name, "- Gear ID:", gearId) local success = false local methods = {} if _G.GetPlayerGearData then local gearData = _G.GetPlayerGearData(player.UserId) if gearData then if not gearData.gearInventory then gearData.gearInventory = {} end local hasGear = false for _, ownedGearId in ipairs(gearData.gearInventory) do if ownedGearId == gearId then hasGear = true break end end if not hasGear then table.insert(gearData.gearInventory, gearId) success = true table.insert(methods, "Direct gear system") print("? Added gear via direct gear system") if _G.SavePlayerGearData then _G.SavePlayerGearData(player) end else print("?? Player already has gear:", gearId) success = true end end end if not success then local GearRemotes = ReplicatedStorage:FindFirstChild("GearRemotes") if GearRemotes then local AddGear = GearRemotes:FindFirstChild("AddGear") if AddGear and AddGear:IsA("RemoteFunction") then local gearSuccess = pcall(function() return AddGear:InvokeServer(player, gearId) end) if gearSuccess then success = true table.insert(methods, "GearRemotes") print("? Added gear via GearRemotes") end end end end if not success and _G.playerData and _G.playerData[player.UserId] then local playerData = _G.playerData[player.UserId] if not playerData.gearInventory then playerData.gearInventory = {} end local hasGear = false for _, ownedGearId in ipairs(playerData.gearInventory) do if ownedGearId == gearId then hasGear = true break end end if not hasGear then table.insert(playerData.gearInventory, gearId) success = true table.insert(methods, "Force playerData") print("? Added gear via force playerData method") end end if success then print("?? Successfully gave gear", gearId, "to", player.Name, "using methods:", table.concat(methods, ", ")) return true else warn("? Failed to give gear", gearId, "to", player.Name, "- All methods failed") return false end end local function giveBrainrotToPlayer(player, brainrotName, amount) print("?? Giving", amount, "x", brainrotName, "to", player.Name) if _G.AddItemToInventory then for i = 1, amount do _G.AddItemToInventory(player.UserId, brainrotName) end print("? Added brainrots via _G.AddItemToInventory") return true end local InventoryRemotes = ReplicatedStorage:FindFirstChild("InventoryRemotes"